import re
import subprocess
from pathlib import Path
text = Path('docs/evaluation.md').read_text(encoding='utf-8')
section_match = re.search(r'^## Deterministic Benchmark Tasks\s*(.*?)(?=^##\s+|\Z)', text, flags=re.M | re.S)
assert section_match, 'missing ## Deterministic Benchmark Tasks section'
section = section_match.group(1)
normalized = re.sub(r'\s+', ' ', section).lower()
sentences = [part.strip() for part in re.split(r'(?<=[.!?])\s+', normalized) if part.strip()]

def has_any(*phrases):
    return any(phrase in normalized for phrase in phrases)

def has_repo_ownership(sentence):
    if re.search(r'\bnot\b.{0,24}\b(?:this repository|this repo|the repository)\b', sentence):
        return False
    oracle_to_repo = re.search(r'\boracles?\b.{0,120}\b(?:belong|belongs|live|lives|reside|resides|stay|stays|owned|kept|stored|maintained)\b.{0,80}\b(?:this repository|this repo|the repository)\b', sentence)
    repo_to_oracle = re.search(r'\b(?:this repository|this repo|the repository)\b.{0,100}\b(?:owns|keeps|stores|contains|holds|maintains|is responsible for)\b.{0,120}\boracles?\b', sentence)
    return bool(oracle_to_repo or repo_to_oracle)

def excludes_runner(sentence):
    return bool(
        re.search(r'\b(?:not|never|outside|rather than|instead of|separate from|apart from)\b.{0,100}\brunner repository\b', sentence)
        or re.search(r'\brunner repository\b.{0,100}\b(?:does not|should not|must not|never)\b.{0,100}\b(?:own|contain|store|hold|keep|maintain|receive)\b', sentence)
    )

def has_runner_as_owner(sentence):
    runner_index = sentence.find('runner repository')
    if runner_index < 0:
        return False
    before_runner = sentence[max(0, runner_index - 40):runner_index]
    if any(marker in before_runner for marker in ('not to the ', 'not in the ', 'rather than the ', 'instead of the ', 'outside the ', 'separate from the ', 'apart from the ')):
        return False
    return bool(
        re.search(r'\boracles?\b.{0,120}\b(?:belong|belongs|live|lives|reside|resides|stay|stays|owned|kept|stored|maintained)\b.{0,80}\brunner repository\b', sentence)
        or re.search(r'\brunner repository\b.{0,100}\b(?:owns|keeps|stores|contains|holds|maintains)\b.{0,120}\boracles?\b', sentence)
    )

oracle_sentences = [sentence for sentence in sentences if 'project-specific' in sentence and re.search(r'\boracles?\b', sentence)]
assert not any(has_runner_as_owner(sentence) for sentence in oracle_sentences), 'project-specific oracles must not be owned by the runner repository'
checks = [
    ('benchmark task path', 'benchmarks/tasks/' in normalized),
    ('project-specific oracle ownership', any(has_repo_ownership(sentence) and excludes_runner(sentence) for sentence in oracle_sentences)),
    ('expected_files boundary', 'expected_files' in normalized),
    ('forbidden_files boundary', 'forbidden_files' in normalized),
    ('boundary and verification separation', 'boundary' in normalized and 'verification' in normalized and 'success' in normalized and has_any('separate', 'separately', 'independent', 'independently', 'distinct', 'apart')),
]
missing = [label for label, ok in checks if not ok]
assert not missing, 'missing required benchmark ownership concepts: ' + ', '.join(missing)
status = subprocess.check_output(['git', 'status', '--porcelain=v1'], text=True)
changed = {line[3:] for line in status.splitlines() if len(line) >= 4}
assert 'docs/evaluation.md' in changed, 'docs/evaluation.md must be changed by this task'
